[package]
name = "literbike"
version = "0.1.0"
edition = "2021"
license = "AGPL-3.0"
repository = "https://github.com/literbike/literbike"

[features]
default = ["quic"]
quic = ["dep:bincode", "dep:bytes", "dep:tracing", "dep:log", "dep:glob", "dep:base64"]
quic-crypto = ["quic"]
full = ["quic", "couchdb", "gates"]
couchdb = ["dep:sled", "dep:utoipa", "dep:utoipa-swagger-ui", "dep:axum", "dep:tower", "dep:tower-http", "dep:base64", "dep:ndarray"]
gates = ["dep:async-trait"]
ipfs = ["dep:ipfs-api-backend-hyper", "dep:cid"]
tensor = ["dep:ndarray", "dep:ndarray-linalg"]

[dependencies]
# Core (always needed)
tokio = { version = "1.41", features = ["full"] }
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"
anyhow = "1.0"
thiserror = "1.0"
env_logger = "0.10"
once_cell = "1.19"

# Async/concurrency
futures = "0.3"
tokio-stream = "0.1"
async-stream = "0.3"
async-channel = "2.5"
crossbeam = "0.8"
crossbeam-channel = "0.5"
sha2 = "0.10"
num-bigint = "0.4"
data-encoding = "2.4"
dashmap = "6.1"

# Time/UUID
chrono = { version = "0.4", features = ["serde"] }
uuid = { version = "1.0", features = ["v4", "serde"] }

# System
nix = { version = "0.27", features = ["socket"] }
libc = "0.2"
cfg-if = "1.0"

# Utils
smallvec = "1.15"
percent-encoding = "2.3"
regex = "1.0"
hex = "0.4"
bs58 = "0.5"

# QUIC feature dependencies
bincode = { version = "1.3", optional = true }
bytes = { version = "1.0", optional = true }
rand = "0.8"
parking_lot = "0.12"
socket2 = { version = "0.5", features = ["all"] }
tracing = { version = "0.1", optional = true }

# CouchDB feature dependencies
sled = { version = "0.34", optional = true }
utoipa = { version = "4.0", optional = true }
utoipa-swagger-ui = { version = "4.0", optional = true }
axum = { version = "0.7", optional = true }
tower = { version = "0.4", optional = true }
tower-http = { version = "0.5", features = ["cors", "trace"], optional = true }
base64 = { version = "0.22", optional = true }

# Gates feature dependencies
async-trait = { version = "0.1", optional = true }

# IPFS feature dependencies
ipfs-api-backend-hyper = { version = "0.6", optional = true }
cid = { version = "0.10", optional = true }

# Tensor feature dependencies
ndarray = { version = "0.15", optional = true }
ndarray-linalg = { version = "0.16", optional = true }

# Optional networking
warp = { version = "0.3", optional = true }
hyper = { version = "1.0", optional = true }
log = { version = "0.4", optional = true }
chacha20poly1305 = { version = "0.10", optional = true }
git2 = { version = "0.19", optional = true }
notify = { version = "6.1", optional = true }
mime = { version = "0.3", optional = true }
glob = { version = "0.3", optional = true }

[workspace]
members = [
    "literbike-py",
    "literbike-ffi",
    "literbike-quic-capi",
	"tools/selfhosted",
	"tools/config_tester",
]

# Binary targets with required features
[[bin]]
name = "couchdb_emulator"
required-features = ["couchdb"]

[[bin]]
name = "litebike"
required-features = ["warp", "git2"]
rand = "0.8"  # For betanet_patterns

use super::quic_engine::{QuicEngine, Role};
use super::quic_error::QuicError;
use super::quic_failure_log as qfail;
use super::quic_protocol::{
    deserialize_decoded_packet_with_dcid_len, ConnectionId, ConnectionState, QuicConnectionState,
    QuicFrame, TransportParameters,
};
use crate::rbcursive::{NetTuple, Protocol as RbProtocol, RbCursor, Signal as RbSignal};
use parking_lot::Mutex;
use socket2::{Domain, Socket, Type};
use std::collections::HashMap;
use std::net::SocketAddr;
use std::sync::Arc;
use tokio::net::UdpSocket as TokioUdpSocket;

pub struct QuicServer {
    socket: Arc<TokioUdpSocket>,
    rb: Arc<Mutex<RbCursor>>,
    connections: Arc<Mutex<HashMap<SocketAddr, Arc<QuicEngine>>>>,
}

impl QuicServer {
    pub async fn bind(addr: SocketAddr) -> Result<Self, QuicError> {
        let socket =
            Socket::new(Domain::for_address(addr), Type::DGRAM, None).map_err(QuicError::Io)?;

        socket.set_reuse_address(true).map_err(QuicError::Io)?;
        #[cfg(unix)]
        socket.set_reuse_port(true).map_err(QuicError::Io)?;

        socket.bind(&addr.into()).map_err(QuicError::Io)?;

        let std_socket: std::net::UdpSocket = socket.into();
        std_socket.set_nonblocking(true).map_err(QuicError::Io)?;

        let tokio_socket = TokioUdpSocket::from_std(std_socket).map_err(QuicError::Io)?;

        Ok(Self {
            socket: Arc::new(tokio_socket),
            rb: Arc::new(Mutex::new(RbCursor::new())),
            connections: Arc::new(Mutex::new(HashMap::new())),
        })
    }

    pub async fn start(&self) -> Result<(), QuicError> {
        let socket = self.socket.clone();
        let connections = self.connections.clone(); // Clone for the spawned task
        let rb_cursor = self.rb.clone();

        // Spawn the UDP receive loop locally — the captured `RbCursor` is not
        // `Send` (contains raw pointers), so we use a local task. Callers must
        // run `start()` inside a `tokio::task::LocalSet` or equivalent.
        tokio::task::spawn_local(async move {
            let mut buf = vec![0u8; 65536]; // Max UDP packet size
            loop {
                match socket.recv_from(&mut buf).await {
                    Ok((len, remote_addr)) => {
                        println!("📡 Received {} bytes from {}", len, remote_addr);
                        let packet_data = &buf[..len];

                        // RbCursive preflight
                        let tuple = NetTuple::from_socket_addr(remote_addr, RbProtocol::HtxQuic);
                        let hint = if packet_data.len() > 0 {
                            vec![packet_data[0]]
                        } else {
                            vec![]
                        };
                        let signal = rb_cursor.lock().recognize(tuple, &hint);
                        println!("🔍 RbCursive signal: {:?}", signal);

                        match signal {
                            RbSignal::Accept(proto) => {
                                println!("✅ Accepted protocol: {:?}", proto);
                                let short_header_dcid_len =
                                    connections.lock().get(&remote_addr).map(|engine| {
                                        engine.get_state().local_connection_id.bytes.len()
                                    });

                                match deserialize_decoded_packet_with_dcid_len(
                                    packet_data,
                                    short_header_dcid_len,
                                ) {
                                    Ok(decoded_packet) => {
                                        let received_packet = decoded_packet.packet.clone();
                                        println!("📦 Deserialized packet with {} frames", received_packet.frames.len());
                                        let engine_arc = {
                                            let mut connections_guard = connections.lock();
                                            connections_guard
                                                .entry(remote_addr)
                                                .or_insert_with(|| {
                                                    // Create a new engine for this connection
                                                    let local_conn_id = ConnectionId {
                                                        bytes: vec![1, 2, 3, 4, 5, 6, 7, 8],
                                                    }; // Dummy
                                                    let remote_conn_id = ConnectionId {
                                                        bytes: vec![8, 7, 6, 5, 4, 3, 2, 1],
                                                    }; // Dummy

                                                    let initial_state = QuicConnectionState {
                                                        local_connection_id: local_conn_id,
                                                        remote_connection_id: remote_conn_id,
                                                        version: 1,
                                                        transport_params:
                                                            TransportParameters::default(),
                                                        streams: Vec::new(),
                                                        sent_packets: Vec::new(),
                                                        received_packets: Vec::new(),
                                                        next_packet_number: 0,
                                                        next_stream_id: 0,
                                                        congestion_window: 14720,
                                                        bytes_in_flight: 0,
                                                        rtt: 100,
                                                        connection_state:
                                                            ConnectionState::Handshaking, // Initial state
                                                    };
                                                    Arc::new(QuicEngine::new(
                                                        Role::Server,
                                                        initial_state,
                                                        socket.clone(),
                                                        remote_addr,
                                                        vec![0; 32], // Dummy private key
                                                    ))
                                                })
                                                .clone()
                                        };

                                        // Process the packet with the engine
                                        match engine_arc.process_decoded_packet(decoded_packet).await {
                                            Ok(()) => {
                                                // If the packet contained a StreamFrame, echo the data back
                                                for frame in received_packet.frames.iter() {
                                                    println!("🎞️ Frame type: {:?}", frame);
                                                    if let QuicFrame::Stream(stream_frame) = frame {
                                                        // Visual QA - Simple file serving
                                                        let data_str = String::from_utf8_lossy(&stream_frame.data);
                                                        println!("📄 Server received request on stream {}: {}", stream_frame.stream_id, data_str);

                                                        let response_data = if data_str.contains("index.css") {
                                                            match std::fs::read("index.css") {
                                                                Ok(d) => d,
                                                                Err(e) => {
                                                                    println!("❌ Failed to read index.css: {}", e);
                                                                    b"/* css not found */".to_vec()
                                                                }
                                                            }
                                                        } else if data_str.contains("bw_test_pattern.png") {
                                                            match std::fs::read("bw_test_pattern.png") {
                                                                Ok(d) => {
                                                                    println!("🖼️ Serving bw_test_pattern.png ({} bytes)", d.len());
                                                                    d
                                                                }
                                                                Err(e) => {
                                                                    println!("❌ Failed to read bw_test_pattern.png: {}", e);
                                                                    b"image not found".to_vec()
                                                                }
                                                            }
                                                        } else {
                                                            // For anything else (like the initial GET /), serve index.html
                                                            match std::fs::read("index.html") {
                                                                Ok(d) => d,
                                                                Err(e) => {
                                                                    println!("❌ Failed to read index.html: {}", e);
                                                                    b"<html><body><h1>QUIC VQA ERROR</h1></body></html>".to_vec()
                                                                }
                                                            }
                                                        };

                                                        // Chunk the data to avoid "Message too long" (UDP limit is 65k, but path MTU is typically ~1350)
                                                        let chunk_size = 1200;
                                                        let total_len = response_data.len();
                                                        let mut offset = 0;
                                                        let mut success = true;

                                                        while offset < total_len {
                                                            let end = (offset + chunk_size).min(total_len);
                                                            let chunk = response_data[offset..end].to_vec();
                                                            if let Err(e) = engine_arc.send_stream_data(stream_frame.stream_id, chunk).await {
                                                                println!("❌ Failed to send VQA stream chunk at offset {}: {}", offset, e);
                                                                success = false;
                                                                break;
                                                            }
                                                            offset = end;
                                                        }

                                                        if success {
                                                            println!("✅ Sent response ({} bytes) in {} chunks on stream {}",
                                                                total_len,
                                                                (total_len + chunk_size - 1) / chunk_size,
                                                                stream_frame.stream_id
                                                            );
                                                        }
                                                    }
                                                }
                                            }
                                            Err(e) => {
                                                qfail::log_error(
                                                    "server",
                                                    "process_packet",
                                                    &e,
                                                    serde_json::json!({"remote": remote_addr, "len": len}),
                                                );
                                                tracing::error!("Error processing packet: {}", e);
                                            }
                                        }
                                    }
                                    Err(e) => {
                                        let quic_err = QuicError::Protocol(e);
                                        qfail::log_error(
                                            "server",
                                            "deserialize",
                                            &quic_err,
                                            serde_json::json!({"remote": remote_addr, "len": len}),
                                        );
                                        tracing::error!("Failed to deserialize packet");
                                    }
                                }
                            }
                            other => {
                                tracing::debug!(target = "rb", ?other, "RbCursive server preflight non-accept signal for packet from {}", remote_addr);
                                // Drop packet if not accepted by RbCursive
                            }
                        }
                    }
                    Err(e) => {
                        let quic_err = QuicError::Io(e);
                        qfail::log_error("server", "recv_from", &quic_err, serde_json::json!({}));
                        tracing::error!("UDP socket receive error");
                    }
                }
            }
        });
        Ok(())
    }

    pub fn local_addr(&self) -> Result<SocketAddr, QuicError> {
        self.socket.local_addr().map_err(QuicError::Io)
    }

    pub async fn accept(&self) -> Option<Arc<QuicEngine>> {
        // This method needs to be re-thought for a multi-connection server.
        // For now, it will just return None, as connections are managed internally.
        // A real accept would block until a new connection is established and return it.
        None
    }

    /// Close endpoint gracefully
    pub async fn close(&self) {
        // Iterate through all active engines and close them
        let connections_guard = self.connections.lock();
        for (_, engine) in connections_guard.iter() {
            engine.close().await;
        }
        // In a real implementation, close the UDP socket
    }
}

use literbike::quic::quic_protocol::{serialize_packet, deserialize_packet, QuicPacket, QuicHeader, QuicFrame, StreamFrame, ConnectionId, QuicPacketType};
use std::net::UdpSocket;
use std::time::Duration;

async fn fetch_resource(socket: &UdpSocket, path: &str, stream_id: u64) -> Result<Vec<u8>, Box<dyn std::error::Error>> {
    let header = QuicHeader {
        r#type: QuicPacketType::ShortHeader,
        version: 1,
        destination_connection_id: ConnectionId { bytes: vec![1, 2, 3, 4, 5, 6, 7, 8] },
        source_connection_id: ConnectionId { bytes: vec![2, 2, 2, 2, 2, 2, 2, 2] },
        packet_number: stream_id * 100, // Just a unique PN
        token: None,
    };

    let frames = vec![QuicFrame::Stream(StreamFrame {
        stream_id,
        offset: 0,
        fin: false,
        data: format!("GET {} HTTP/3\r\nHost: localhost\r\n\r\n", path).into_bytes(),
    })];

    let packet = QuicPacket { header, frames, payload: Vec::new() };
    let serialized = serialize_packet(&packet)?;
    socket.send(&serialized)?;

    let mut buf = [0u8; 65536];
    let mut data = Vec::new();

    // For large files (like the PNG), we need to read many packets
    // Our VQA server currently sends the whole file in one stream frame,
    // which might be split into multiple UDP packets by the network stack or QUIC layer.
    // However, our FOUNDATIONAL codec currently tries to fit it in one if possible?
    // Actually, std::fs::read returns 554kb, which is way too big for one UDP packet.
    // Our QuicEngine::send_stream_data MUST be splitting it.

    let start = std::time::Instant::now();
    while start.elapsed() < Duration::from_secs(3) {
        match socket.recv(&mut buf) {
            Ok(len) => {
                if let Ok(p) = deserialize_packet(&buf[..len]) {
                    for frame in p.frames {
                        if let QuicFrame::Stream(s) = frame {
                            if s.stream_id == stream_id {
                                data.extend_from_slice(&s.data);
                            }
                        }
                    }
                } else {
                    // Raw fallback
                }
            }
            Err(_) => break,
        }
    }
    Ok(data)
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let socket = UdpSocket::bind("0.0.0.0:0")?;
    socket.connect("127.0.0.1:4433")?;
    socket.set_read_timeout(Some(Duration::from_millis(500)))?;

    println!("🚀 Starting QUIC TDD Full Stack Verification (Robust)");

    // 1. Fetch index.html
    let html = fetch_resource(&socket, "/", 1).await?;
    println!("✅ index.html: {} bytes", html.len());

    // 2. Fetch index.css
    let css = fetch_resource(&socket, "/index.css", 3).await?;
    println!("✅ index.css: {} bytes", css.len());

    // 3. Fetch bw_test_pattern.png
    println!("📥 Requesting PNG (this might take a second)...");
    let png = fetch_resource(&socket, "/bw_test_pattern.png", 5).await?;
    println!("✅ bw_test_pattern.png: {} bytes", png.len());

    if html.len() > 100 && css.len() > 100 && png.len() > 10000 {
        println!("\n✨✨ ALL ASSETS VERIFIED OVER QUIC ✨✨");
        println!("The server is READY for Chrome QA.");
    } else {
        println!("\n❌ Verification failed. Missing or small assets.");
        if png.len() == 0 {
            println!("   TIP: Check if bw_test_pattern.png is splitting across many packets that the codec fails to handle.");
        }
    }

    Ok(())
}

//! Lean HTTP/1.1 Server - relaxfactory pattern (Simplified)
//!
//! Zero-copy, minimal-allocation HTTP server using POSIX select reactor
//! Pattern borrowed from relaxfactory RxfBenchMarkHttpServer and ShardNode2

use crate::reactor::{Reactor, EventHandler, Attachment, Interest};
use super::session::{HttpSession, SessionState};
use super::header_parser::{HttpStatus, headers, mime};

use std::collections::HashMap;
use std::io::{self, Read, Write};
use std::net::{TcpListener, TcpStream};
use std::os::fd::{AsRawFd, FromRawFd, IntoRawFd, RawFd};
use std::sync::Arc;
use parking_lot::RwLock;

/// HTTP request handler trait
pub trait HttpHandler: Send + Sync {
    /// Handle HTTP request, write response to session
    fn handle(&self, session: &mut HttpSession);
}

/// Simple closure-based handler
pub struct FnHandler<F>(pub F) where F: Fn(&mut HttpSession) + Send + Sync;

impl<F> HttpHandler for FnHandler<F>
where
    F: Fn(&mut HttpSession) + Send + Sync,
{
    fn handle(&self, session: &mut HttpSession) {
        (self.0)(session)
    }
}

/// HTTP Server session
pub struct HttpSessionContainer {
    pub session: HttpSession,
}

/// HTTP Server event handler (like relaxfactory Impl)
pub struct HttpEventHandler {
    /// Request router: path -> handler
    routes: Arc<RwLock<HashMap<String, Arc<dyn HttpHandler>>>>,

    /// Default handler (if no route matches)
    default_handler: Option<Arc<dyn HttpHandler>>,

    /// Server info
    server_name: String,
}

impl HttpEventHandler {
    /// Create new HTTP event handler
    pub fn new(server_name: &str) -> Self {
        Self {
            routes: Arc::new(RwLock::new(HashMap::new())),
            default_handler: None,
            server_name: server_name.to_string(),
        }
    }

    /// Register route handler
    pub fn register_route<H: HttpHandler + 'static>(&self, path: &str, handler: H) {
        self.routes.write().insert(path.to_string(), Arc::new(handler));
    }

    /// Register closure handler
    pub fn register_route_fn<F>(&self, path: &str, handler: F)
    where
        F: Fn(&mut HttpSession) + Send + Sync + 'static,
    {
        self.register_route(path, FnHandler(handler));
    }

    /// Set default handler
    pub fn set_default_handler<H: HttpHandler + 'static>(&mut self, handler: H) {
        self.default_handler = Some(Arc::new(handler));
    }

    /// Set default handler from closure
    pub fn set_default_handler_fn<F>(&mut self, handler: F)
    where
        F: Fn(&mut HttpSession) + Send + Sync + 'static,
    {
        self.set_default_handler(FnHandler(handler));
    }

    /// Route request to handler
    fn route_request(&self, session: &mut HttpSession) {
        if let Some(path) = session.path() {
            // Strip query string for routing
            let path = path.split('?').next().unwrap_or(path);

            let routes = self.routes.read();
            if let Some(handler) = routes.get(path) {
                handler.handle(session);
                return;
            }
        }

        // Default handler
        if let Some(ref handler) = self.default_handler {
            handler.handle(session);
        } else {
            // Default 404
            session.prepare_response(
                HttpStatus::Status404,
                mime::TEXT_PLAIN,
                b"404 Not Found",
            );
        }
    }
}

impl EventHandler<HttpSessionContainer, HttpEventHandler> for HttpEventHandler {
    fn on_read(&mut self, fd: RawFd, attachment: &mut Attachment<HttpSessionContainer, HttpEventHandler>) {
        let session = &mut attachment.session.session;

        // Read from socket - create temporary stream for reading
        let mut buf = [0u8; 1024];
        let n = unsafe {
            let mut stream = TcpStream::from_raw_fd(fd);
            let result = stream.read(&mut buf);
            let _ = stream.into_raw_fd();
            result
        };

        match n {
            Ok(0) => {
                // EOF - close connection
                attachment.interest.read = false;
                attachment.interest.write = false;
            }
            Ok(bytes_read) => {
                session.parser.append(&buf[..bytes_read]);

                // Try to parse headers
                match session.try_parse_headers() {
                    Ok(true) => {
                        // Headers complete
                        if session.body_complete() {
                            session.finish_reading_body();
                            self.route_request(session);
                        }
                    }
                    Ok(false) => {
                        // Need more data
                    }
                    Err(_) => {
                        // Parse error - send 400
                        session.prepare_response(
                            HttpStatus::Status400,
                            mime::TEXT_PLAIN,
                            b"400 Bad Request",
                        );
                    }
                }
            }
            Err(_) => {
                // Read error
                attachment.interest.read = false;
            }
        }

        // Update interest
        if session.wants_read() {
            attachment.interest.read = true;
        }
        if session.wants_write() {
            attachment.interest.write = true;
        }
    }

    fn on_write(&mut self, fd: RawFd, attachment: &mut Attachment<HttpSessionContainer, HttpEventHandler>) {
        let session = &mut attachment.session.session;

        if session.response_buffer.is_empty() {
            attachment.interest.write = false;
            return;
        }

        // Write to socket
        let result = unsafe {
            let mut stream = TcpStream::from_raw_fd(fd);
            stream.set_nonblocking(true).ok();
            let result = stream.write(&session.response_buffer);
            let _ = stream.into_raw_fd();
            result
        };

        match result {
            Ok(bytes_written) => {
                if bytes_written >= session.response_buffer.len() {
                    session.response_buffer.clear();

                    if session.keep_alive {
                        session.reset();
                    } else {
                        session.state = SessionState::Done;
                    }
                } else {
                    session.response_buffer.drain(..bytes_written);
                }
            }
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {
                // Try again later
            }
            Err(_) => {
                attachment.interest.write = false;
            }
        }

        // Update interest
        if session.wants_write() && !session.response_buffer.is_empty() {
            attachment.interest.write = true;
        } else {
            attachment.interest.write = false;
        }

        if session.wants_read() {
            attachment.interest.read = true;
        } else {
            attachment.interest.read = false;
        }
    }

    fn on_accept(&mut self, fd: RawFd, attachment: &mut Attachment<HttpSessionContainer, HttpEventHandler>) {
        // Accept new connection
        let listener = unsafe {
            TcpListener::from_raw_fd(fd)
        };

        match listener.accept() {
            Ok((stream, _addr)) => {
                stream.set_nonblocking(true).ok();
                let new_fd = stream.as_raw_fd();

                log::info!("Accepted connection on FD {}", new_fd);

                // Note: In a full implementation, we would enqueue the new connection
                // with the reactor here. For now, we just log it.

                // Prevent TcpListener from closing FD
                let _ = stream.into_raw_fd();
            }
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {}
            Err(e) => {
                log::error!("Accept error: {}", e);
            }
        }

        // Prevent TcpListener from closing FD
        let _ = listener.into_raw_fd();
    }

    fn on_error(&mut self, fd: RawFd, _attachment: &mut Attachment<HttpSessionContainer, HttpEventHandler>, error: io::Error) {
        log::error!("HTTP error on FD {}: {}", fd, error);
    }
}

/// Lean HTTP Server (like RxfBenchMarkHttpServer)
pub struct HttpServer {
    /// Server name
    name: String,

    /// Bind address
    addr: String,

    /// Port
    port: u16,

    /// Event handler
    handler: Arc<HttpEventHandler>,

    /// TCP Listener
    listener: Option<TcpListener>,

    /// Running state
    running: bool,
}

impl HttpServer {
    /// Create new HTTP server
    pub fn new(name: &str, addr: &str, port: u16) -> Self {
        Self {
            name: name.to_string(),
            addr: addr.to_string(),
            port,
            handler: Arc::new(HttpEventHandler::new(name)),
            listener: None,
            running: false,
        }
    }

    /// Get server name (like RxfBenchMarkHttpServer.getName)
    pub fn name(&self) -> &str {
        &self.name
    }

    /// Get bind address
    pub fn addr(&self) -> &str {
        &self.addr
    }

    /// Get port
    pub fn port(&self) -> u16 {
        self.port
    }

    /// Register route handler
    pub fn route<H: HttpHandler + 'static>(&self, path: &str, handler: H) {
        self.handler.register_route(path, handler);
    }

    /// Register closure handler
    pub fn route_fn<F>(&self, path: &str, handler: F)
    where
        F: Fn(&mut HttpSession) + Send + Sync + 'static,
    {
        self.handler.register_route_fn(path, handler);
    }

    /// Bind to address (like RxfBenchMarkHttpServer.start)
    pub fn bind(&mut self) -> io::Result<()> {
        let bind_addr = format!("{}:{}", self.addr, self.port);
        let listener = TcpListener::bind(&bind_addr)?;
        listener.set_nonblocking(true)?;

        log::info!("HTTP Server '{}' listening on {}", self.name, bind_addr);

        self.listener = Some(listener);
        Ok(())
    }

    /// Get handler for reactor
    pub fn handler(&self) -> Arc<HttpEventHandler> {
        self.handler.clone()
    }

    /// Get listener FD for manual registration with reactor
    pub fn listener_fd(&self) -> Option<RawFd> {
        self.listener.as_ref().map(|l| l.as_raw_fd())
    }

    /// Stop server
    pub fn stop(&mut self) {
        self.running = false;
        if let Some(ref listener) = self.listener {
            log::info!("HTTP Server '{}' stopping", self.name);
            // Drop listener
            self.listener = None;
        }
    }

    /// Check if running
    pub fn is_running(&self) -> bool {
        self.running
    }
}

/// Helper: send simple HTTP response
pub fn send_response(session: &mut HttpSession, status: HttpStatus, content_type: &str, body: &[u8]) {
    session.prepare_response(status, content_type, body);
}

/// Helper: send JSON response
pub fn send_json(session: &mut HttpSession, status: HttpStatus, json: &str) {
    session.prepare_response(status, mime::APPLICATION_JSON, json.as_bytes());
}

/// Helper: send HTML response
pub fn send_html(session: &mut HttpSession, status: HttpStatus, html: &str) {
    session.prepare_response(status, mime::TEXT_HTML, html.as_bytes());
}

/// Helper: send redirect
pub fn send_redirect(session: &mut HttpSession, location: &str) {
    session.parser.set_status(HttpStatus::Status302);
    session.parser.set_header(headers::LOCATION, location);
    session.prepare_response(HttpStatus::Status302, mime::TEXT_PLAIN, b"Redirect");
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_server_creation() {
        let server = HttpServer::new("test", "127.0.0.1", 8080);
        assert_eq!(server.name(), "test");
        assert_eq!(server.port(), 8080);
        assert!(!server.is_running());
    }

    #[test]
    fn test_route_registration() {
        let server = HttpServer::new("test", "127.0.0.1", 8080);

        server.route_fn("/test", |session| {
            send_response(session, HttpStatus::Status200, mime::TEXT_PLAIN, b"OK");
        });

        // Route should be registered
        let routes = server.handler.routes.read();
        assert!(routes.contains_key("/test"));
    }

    #[test]
    fn test_send_helpers() {
        let mut session = HttpSession::new();

        send_response(&mut session, HttpStatus::Status200, mime::TEXT_PLAIN, b"Hello");
        assert!(session.wants_write());

        session.reset();
        send_json(&mut session, HttpStatus::Status200, r#"{"key":"value"}"#);
        assert!(session.wants_write());

        session.reset();
        send_redirect(&mut session, "/new-location");
        assert_eq!(session.parser.status(), Some(HttpStatus::Status302));
    }
}

//! Lean HTTP/1.1 Server Example - relaxfactory pattern
//!
//! This example demonstrates a minimal HTTP server using the literbike HTTP module,
//! borrowing the relaxfactory NIO reactor pattern.
//!
//! Run with: cargo run --example http_server

use literbike::http::header_parser::{mime, HttpMethod, HttpStatus};
use literbike::http::{send_json, send_response, HttpServer, HttpSession, HttpSessionContainer};

fn main() -> std::io::Result<()> {
    env_logger::init();

    println!("=== Literbike Lean HTTP Server ===");
    println!("Pattern borrowed from relaxfactory (Java NIO HTTP server)");
    println!();

    // Create server
    let mut server = HttpServer::new("literbike-example", "127.0.0.1", 8888);

    // Register routes
    server.route_fn("/", |session| {
        send_response(
            session,
            HttpStatus::Status200,
            mime::TEXT_HTML,
            b"<html><body><h1>Hello from Literbike!</h1><p>Lean HTTP/1.1 server inspired by relaxfactory</p></body></html>",
        );
    });

    server.route_fn("/api/health", |session| {
        send_json(
            session,
            HttpStatus::Status200,
            r#"{"status":"healthy","server":"literbike"}"#,
        );
    });

    server.route_fn("/api/echo", |session| {
        // Echo back the request method and path
        let method = session.method().map(|m| m.as_str()).unwrap_or("UNKNOWN");
        let path = session.path().unwrap_or("/unknown");
        let response = format!(r#"{{"method":"{}","path":"{}"}}"#, method, path);
        send_json(session, HttpStatus::Status200, &response);
    });

    server.route_fn("/api/data", |session| {
        // Only handle GET requests
        if session.method() == Some(HttpMethod::GET) {
            send_json(
                session,
                HttpStatus::Status200,
                r#"{"items":[{"id":1,"name":"Item 1"},{"id":2,"name":"Item 2"}]}"#,
            );
        } else {
            send_response(
                session,
                HttpStatus::Status405,
                mime::TEXT_PLAIN,
                b"Method Not Allowed",
            );
        }
    });

    // Default handler (404 for unmatched routes)
    // Note: For this example, unmatched routes will return 404 from the built-in default
    // To set a custom default handler, you would need to access the handler before wrapping in Arc
    // server.handler().set_default_handler_fn(|session| { ... });

    println!(
        "Server '{}' starting on http://{}:{}",
        server.name(),
        server.addr(),
        server.port()
    );
    println!();
    println!("Available endpoints:");
    println!("  GET  /              - HTML welcome page");
    println!("  GET  /api/health    - Health check (JSON)");
    println!("  GET  /api/echo      - Echo request info (JSON)");
    println!("  GET  /api/data      - Sample data (JSON)");
    println!();
    println!("Try: curl http://127.0.0.1:8888/api/health");
    println!();

    // Note: This example shows the API usage
    // For a full running server, you would integrate with the reactor:
    //
    // let mut reactor: Reactor<HttpSessionContainer, HttpEventHandler> = Reactor::new()?;
    // server.bind()?;
    // if let Some(fd) = server.listener_fd() {
    //     reactor.enqueue_register(
    //         fd,
    //         HttpSessionContainer { session: HttpSession::new() },
    //         server.handler(),
    //         Interest::ACCEPT,
    //     );
    //     reactor.run(server.handler())?;
    // }

    println!("Note: This example demonstrates the API.");
    println!("To run a full server, uncomment the reactor integration code in the example.");

    Ok(())
}
